// SPDX-License-Identifier: MIT
pragma solidity ^0.8.21;

contract Stage1Token {
    address payable public owner;
    
    string private _name = "Test Token";
    string private _symbol = "TTK";
    uint128 private _price = 600;
    uint256 private _totalSupply;
    
    mapping(address => uint256) private _balances;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Mint(address indexed to, uint256 value);
    event Sell(address indexed from, uint256 value);

    constructor() {
        owner = payable(msg.sender);
    }

    receive() external payable {}
    fallback() external payable {}

    function totalSupply() public view returns (uint256) { return _totalSupply; }
    function balanceOf(address account) public view returns (uint256) { return _balances[account]; }
    function getName() public view returns (string memory) { return _name; }
    function getSymbol() public view returns (string memory) { return _symbol; }
    function getPrice() public view returns (uint128) { return _price; }

    function transfer(address to, uint256 value) public returns (bool) {
        require(_balances[msg.sender] >= value, "Insufficient balance");
        _balances[msg.sender] -= value;
        _balances[to] += value;
        emit Transfer(msg.sender, to, value);
        return true;
    }

    function mint(address to, uint256 value) public returns (bool) {
        require(msg.sender == owner, "Only owner");
        _totalSupply += value;
        _balances[to] += value;
        emit Mint(to, value);
        return true;
    }

    function sell(uint256 value) public returns (bool) {
        // 1. CHECKS
        require(_balances[msg.sender] >= value, "Insufficient balance");
        uint256 ethToReturn = value * _price;
        require(address(this).balance >= ethToReturn, "Contract out of ETH");
        
        // 2. EFFECTS (Deduct balance before sending ETH to prevent reentrancy)
        _balances[msg.sender] -= value;
        _totalSupply -= value;
        
        // 3. INTERACTIONS
        (bool success, ) = payable(msg.sender).call{value: ethToReturn}("");
        require(success, "ETH transfer failed");
        
        emit Sell(msg.sender, value);
        return true;
    }

    function close() public {
        require(msg.sender == owner, "Only owner");

        uint256 balance = address(this).balance;
        if (balance > 0) {
            (bool success, ) = owner.call{value: balance}("");
            require(success, "ETH transfer failed");
        }
    }
}

